#!/usr/bin/env node

/**
 * Safe, opt-in migrator for exact legacy AI Lab scaffold template instances.
 * - Default: report-only
 * - --apply: rewrites only exact-signature files
 */

const fs = require('fs');
const path = require('path');
const glob = require('glob');

const ROOT = process.cwd();
const REPORT = path.join(ROOT, 'automation', 'reports', 'ai-lab-safe-scaffold-migrator-latest.json');
const APPLY = process.argv.includes('--apply');

const EXACT_MARKERS = [
  "AI Lab - Auto Recovery",
  "This page was auto-generated by the AI Lab integrity guardian after detecting a missing route implementation.",
  "Customize this tool with domain-specific controls and scoring logic.",
];

function toTitleFromRel(rel) {
  return rel
    .split(/[/-]/)
    .filter(Boolean)
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
    .join(' ');
}

function layoutImportPath(rel) {
  const depth = rel.split('/').filter(Boolean).length;
  return `${'../'.repeat(depth + 1)}components/ai-lab/AILabToolLayout`;
}

function toComponentName(rel) {
  const name = rel
    .split(/[/-]/)
    .filter(Boolean)
    .map((p) => p.charAt(0).toUpperCase() + p.slice(1).replace(/[^a-zA-Z0-9]/g, ''))
    .join('');
  return `${name || 'AiLabTool'}Page`;
}

function buildReplacement(rel) {
  const title = toTitleFromRel(rel);
  const importPath = layoutImportPath(rel);
  const componentName = toComponentName(rel);
  return `import type { Metadata } from 'next';
import { AILabToolLayout } from '${importPath}';

export const metadata: Metadata = {
  title: ${JSON.stringify(title)},
  description: 'AI Lab tool scaffold upgraded by safe migrator.',
};

export default function ${componentName}() {
  return (
    <div className="bg-slate-950/90">
      <AILabToolLayout
        title={${JSON.stringify(title)}}
        subtitle="Upgraded from legacy auto-recovery scaffold. Replace placeholders with real controls and scoring."
      >
        <div className="space-y-6">
          <section className="rounded-2xl border border-slate-800/80 bg-slate-900/80 p-5">
            <p className="text-xs font-semibold uppercase tracking-wide text-slate-300">Inputs</p>
            <p className="mt-2 text-sm text-slate-400">Add domain inputs and wire state/actions.</p>
          </section>
          <section className="rounded-2xl border border-slate-800/80 bg-slate-900/80 p-5">
            <p className="text-xs font-semibold uppercase tracking-wide text-slate-300">Score</p>
            <p className="mt-2 text-4xl font-bold text-emerald-300">
              —<span className="ml-1 text-base font-semibold text-slate-400">/100</span>
            </p>
          </section>
        </div>
      </AILabToolLayout>
    </div>
  );
}
`;
}

function main() {
  const files = glob
    .sync('app/ai-lab/**/page.tsx', { cwd: ROOT, nodir: true })
    .filter((f) => f !== 'app/ai-lab/page.tsx');
  const candidates = [];
  const migrated = [];

  for (const relFile of files) {
    const full = path.join(ROOT, relFile);
    const text = fs.readFileSync(full, 'utf8');
    const isExact = EXACT_MARKERS.every((m) => text.includes(m));
    if (!isExact) continue;

    const relRoute = relFile.replace(/^app\/ai-lab\//, '').replace(/\/page\.tsx$/, '');
    candidates.push(relFile);

    if (!APPLY) continue;
    fs.writeFileSync(full, buildReplacement(relRoute), 'utf8');
    migrated.push(relFile);
  }

  const report = {
    at: new Date().toISOString(),
    apply: APPLY,
    exactTemplateCandidates: candidates.length,
    migratedCount: migrated.length,
    candidates,
    migrated,
  };
  fs.mkdirSync(path.dirname(REPORT), { recursive: true });
  fs.writeFileSync(REPORT, JSON.stringify(report, null, 2));
  console.log(
    `[ai-lab-safe-scaffold-migrator] candidates=${candidates.length} migrated=${migrated.length} apply=${APPLY}`
  );
}

main();
